const url = 'https://dev.lovestyle.co/api/payments/v1/bot/search';
const bearerToken = 'mnst37vtkNbKoMGlew9dIM3EP7GT2x2vwIN4OdNGNtU=';
const totalRequests = 100; 

const requestBody = {
  email: 'antonioefuturemedia+test18@gmail.com',
};

const results = [];

for (let i = 1; i <= totalRequests; i++) {
  try {
    const response = await this.helpers.httpRequest({
      method: 'POST',
      url,
      headers: {
        Authorization: `Bearer ${bearerToken}`,
        'Content-Type': 'application/json',
      },
      body: requestBody,
      json: true,
    });

    results.push({
      json: {
        attempt: i,
        success: true,
        response,
      },
    });
  } catch (error) {
    results.push({
      json: {
        attempt: i,
        success: false,
        error: error.message,
        details: error.response?.body || null,
      },
    });

    // stop execution on first error
    break;
  }
}

return results;

